           if (uRipples[i].rippleType > 0.5) {
               curSpeed = 18.0;
               curWidth = 2.5;         // 流星波纹更尖锐
               curFadeDist = 18.0;     // 衰减更慢，更明显
               elevationScale = 1.8;   // 高度影响更大
           }

